@namespace Lumeo
@using Lumeo.Services
@implements IDisposable
@inject ThemeService Theme
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<Tooltip>
    <TooltipTrigger AsChild>
        <ChildContentSlot Context="slot">
            <button type="button"
                    class="@CssClass"
                    @onclick="ToggleTheme"
                    aria-label="@L["Theme.Toggle"]"
                    aria-pressed="@_isDark.ToString().ToLowerInvariant()"
                    @attributes="MergeAttrs(slot.Attributes)">
                @if (_isDark)
                {
                    <SvgGlyph Svg="@(LumeoIcons.Sun)" class="h-4 w-4" aria-hidden="true" />
                }
                else
                {
                    <SvgGlyph Svg="@(LumeoIcons.Moon)" class="h-4 w-4" aria-hidden="true" />
                }
            </button>
        </ChildContentSlot>
    </TooltipTrigger>
    <TooltipContent>@L["Theme.Toggle"]</TooltipContent>
</Tooltip>

@code {
    /// <summary>Additional CSS classes merged onto the toggle button.</summary>
    [Parameter] public string? Class { get; set; }

    /// <summary>
    /// When <c>true</c> (default) the toggle walks the full three-way mode cycle
    /// (System → Dark → Light). Set to <c>false</c> for a binary Light ↔ Dark
    /// toggle: every click visibly changes the theme — the System step is skipped
    /// (useful in app shells where an "invisible" System→Dark click reads as a
    /// broken button when the OS is already dark).
    /// </summary>
    [Parameter] public bool IncludeSystem { get; set; } = true;
    /// <summary>Captures unmatched attributes and applies them to the toggle button,
    /// merged with the Tooltip AsChild slot's own attributes.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _isDark;
    private bool _disposed;

    // Merge the consumer's AdditionalAttributes with the Tooltip AsChild slot's
    // attributes (aria-describedby while open) onto the single button element.
    private Dictionary<string, object> MergeAttrs(IReadOnlyDictionary<string, object> slotAttrs)
    {
        var d = new Dictionary<string, object>();
        if (AdditionalAttributes is not null)
            foreach (var kv in AdditionalAttributes) d[kv.Key] = kv.Value;
        foreach (var kv in slotAttrs) d[kv.Key] = kv.Value;
        return d;
    }

    private string CssClass => Cx.Merge(
        "inline-flex items-center justify-center h-9 w-9 cursor-pointer rounded-md border border-input bg-background shadow-sm hover:bg-accent hover:text-accent-foreground transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        Class);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            try
            {
                await Theme.InitializeAsync();
            }
            catch (JSDisconnectedException) { return; }
            catch (ObjectDisposedException) { return; }
            // The awaits above can yield long enough for the component to be
            // disposed before this tail runs. Without this guard we would
            // re-subscribe to the shared ThemeService event (a leak) and call
            // StateHasChanged on a torn-down component.
            if (_disposed) return;
            _isDark = Theme.IsDark;
            Theme.OnThemeChanged += OnThemeChanged;
            StateHasChanged();
        }
    }

    private async Task ToggleTheme()
    {
        // No optimistic `_isDark = !_isDark` flip: the mode cycle is three-way
        // (System -> Dark -> Light -> System), so a binary negation shows the
        // wrong icon for a System->Dark step until the async correction lands.
        // OnThemeChanged (raised synchronously at the end of ToggleModeAsync once
        // IsDark is re-read) is the single source of truth and updates the icon
        // exactly once to the resolved state.
        if (IncludeSystem)
        {
            await Theme.ToggleModeAsync();
        }
        else
        {
            // Binary mode: jump straight to the opposite resolved appearance so a
            // single click always produces a visible change.
            await Theme.SetModeAsync(_isDark ? ThemeMode.Light : ThemeMode.Dark);
        }
    }

    private void OnThemeChanged()
    {
        _isDark = Theme.IsDark;
        InvokeAsync(StateHasChanged);
    }

    public void Dispose()
    {
        _disposed = true;
        Theme.OnThemeChanged -= OnThemeChanged;
    }
}
